+		go func() {
+			defer wg.Done()
+			<-start
+			defer func() {
+				if r := recover(); r != nil {
+					select {
+					case panicCh <- r:
+					default:
+					}
+				}
+			}()
+
+			for range emitsPerWorker {
+				detector.handleLimitEvent(event)
+				runtime.Gosched()
+			}
+		}()
+	}
+
+	wg.Add(1)
+	go func() {
+		defer wg.Done()
+		<-start
+		runtime.Gosched()
+		detector.Stop()
+	}()
+
+	close(start)
+	wg.Wait()
+
+	select {
+	case p := <-panicCh:
+		t.Fatalf("handleLimitEvent panicked during concurrent Stop: %v", p)
+	default:
+	}
+}

